module top_module(in1, in2, enable, out);input [3:0] in1;
  input [3:0] in2;
  input enable;
  output [3:0] out;

  wire [3:0] obf_result;

  assign obf_result = in1 * in2; // multiply the two input vectors

  assign out = enable ? obf_result : 4'b0; // output the obf_result if enable is high, otherwise output 0

endmodule
